if has_error {
    let error_message = read_abi_offset(data, error_offset_index)
        .and_then(|offset| read_abi_string(data, offset))
        .unwrap_or_default();
    return if error_message.is_empty() {
        Err(LLM_HAS_ERROR_PREFIX.to_string())
    } else {
        Err(format!("{LLM_HAS_ERROR_PREFIX}: {error_message}"))
    };
}
